export default {
  wrapper: "",
  inner: "",
  label: {
    wrapper: "flex content-center items-center justify-between",
    base: "block font-medium text-gray-700 dark:text-gray-200",
    required: `after:content-['*'] after:ms-0.5 after:text-red-500 dark:after:text-red-400`
  },
  size: {
    "2xs": "text-xs",
    "xs": "text-xs",
    "sm": "text-sm",
    "md": "text-sm",
    "lg": "text-sm",
    "xl": "text-base"
  },
  container: "mt-1 relative",
  description: "text-gray-500 dark:text-gray-400",
  hint: "text-gray-500 dark:text-gray-400",
  help: "mt-2 text-gray-500 dark:text-gray-400",
  error: "mt-2 text-red-500 dark:text-red-400",
  default: {
    size: "sm"
  }
};
<template>
  <div :class="ui.wrapper" v-bind="attrs">
    <div :class="ui.inner">
      <div v-if="label || $slots.label" :class="[ui.label.wrapper, size]">
        <label :for="inputId" :class="[ui.label.base, required ? ui.label.required : '']">
          <slot v-if="$slots.label" name="label" v-bind="{ error, label, name, hint, description, help }" />
          <template v-else>{{ label }}</template>
        </label>
        <span v-if="hint || $slots.hint" :class="[ui.hint]">
          <slot v-if="$slots.hint" name="hint" v-bind="{ error, label, name, hint, description, help }" />
          <template v-else>{{ hint }}</template>
        </span>
      </div>

      <p v-if="description || $slots.description" :class="[ui.description, size]">
        <slot v-if="$slots.description" name="description" v-bind="{ error, label, name, hint, description, help }" />
        <template v-else>
          {{ description }}
        </template>
      </p>
    </div>

    <div :class="[label ? ui.container : '']">
      <slot v-bind="{ error }" />

      <p v-if="typeof error === 'string' && error" :class="[ui.error, size]">
        <slot v-if="$slots.error" name="error" v-bind="{ error, label, name, hint, description, help }" />
        <template v-else>
          {{ error }}
        </template>
      </p>
      <p v-else-if="help || $slots.help" :class="[ui.help, size]">
        <slot v-if="$slots.help" name="help" v-bind="{ error, label, name, hint, description, help }" />
        <template v-else>
          {{ help }}
        </template>
      </p>
    </div>
  </div>
</template>

<script>
import { computed, defineComponent, provide, inject, ref, toRef } from "vue";
import { useUI } from "../../composables/useUI";
import { mergeConfig } from "../../utils";
import appConfig from "#build/app.config";
import { formGroup } from "#ui/ui.config";
import { useId } from "#imports";
const config = mergeConfig(appConfig.ui.strategy, appConfig.ui.formGroup, formGroup);
export default defineComponent({
  inheritAttrs: false,
  props: {
    name: {
      type: String,
      default: null
    },
    size: {
      type: String,
      default: null,
      validator(value) {
        return Object.keys(config.size).includes(value);
      }
    },
    label: {
      type: String,
      default: null
    },
    description: {
      type: String,
      default: null
    },
    required: {
      type: Boolean,
      default: false
    },
    help: {
      type: String,
      default: null
    },
    error: {
      type: [String, Boolean],
      default: null
    },
    hint: {
      type: String,
      default: null
    },
    class: {
      type: [String, Object, Array],
      default: () => ""
    },
    ui: {
      type: Object,
      default: () => ({})
    },
    eagerValidation: {
      type: Boolean,
      default: false
    }
  },
  setup(props) {
    const { ui, attrs } = useUI("formGroup", toRef(props, "ui"), config, toRef(props, "class"));
    const formErrors = inject("form-errors", null);
    const error = computed(() => {
      return props.error && typeof props.error === "string" || typeof props.error === "boolean" ? props.error : formErrors?.value?.find((error2) => error2.path === props.name)?.message;
    });
    const size = computed(() => ui.value.size[props.size ?? config.default.size]);
    const inputId = ref(useId());
    provide("form-group", {
      error,
      inputId,
      name: computed(() => props.name),
      size: computed(() => props.size),
      eagerValidation: computed(() => props.eagerValidation)
    });
    return {
      // eslint-disable-next-line vue/no-dupe-keys
      ui,
      attrs,
      inputId,
      // eslint-disable-next-line vue/no-dupe-keys
      size,
      // eslint-disable-next-line vue/no-dupe-keys
      error
    };
  }
});
</script>
<template>
  <div class="px-4 py-6">
    <!-- Header -->
    <div class="mb-6">
      <h1 class="text-2xl font-bold text-gray-900">Mon profil</h1>
    </div>

    <!-- Profile Card -->
    <div class="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
      <div class="flex items-center gap-4 mb-6">
        <div class="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center">
          <span class="text-2xl font-bold text-green-700">{{ authStore.initials }}</span>
        </div>
        <div>
          <h2 class="text-xl font-bold text-gray-900">{{ authStore.fullName }}</h2>
          <p class="text-gray-500">{{ authStore.user?.email }}</p>
          <UBadge color="green" variant="soft" class="mt-1">🚚 Livreur</UBadge>
        </div>
      </div>

      <!-- Stats -->
      <div class="grid grid-cols-3 gap-4 p-4 bg-gray-50 rounded-xl">
        <div class="text-center">
          <p class="text-2xl font-bold text-gray-900">{{ agentStats.totalDeliveries }}</p>
          <p class="text-xs text-gray-500">Livraisons</p>
        </div>
        <div class="text-center">
          <div class="flex items-center justify-center gap-1">
            <Icon name="lucide:star" class="w-5 h-5 text-amber-500 fill-current" />
            <p class="text-2xl font-bold text-gray-900">{{ agentStats.rating }}</p>
          </div>
          <p class="text-xs text-gray-500">Note</p>
        </div>
        <div class="text-center">
          <p class="text-2xl font-bold text-gray-900">{{ agentStats.zone }}</p>
          <p class="text-xs text-gray-500">Zone</p>
        </div>
      </div>
    </div>

    <!-- Contact Info -->
    <div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100 mb-6">
      <h3 class="font-semibold text-gray-900 mb-4">Informations de contact</h3>

      <div class="space-y-4">
        <div class="flex items-center gap-3">
          <div class="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center">
            <Icon name="lucide:phone" class="w-5 h-5 text-gray-500" />
          </div>
          <div>
            <p class="text-xs text-gray-500">Téléphone</p>
            <p class="font-medium text-gray-900">{{ agentStats.phone || authStore.user?.phone || '-' }}</p>
          </div>
        </div>

        <div class="flex items-center gap-3">
          <div class="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center">
            <Icon name="lucide:mail" class="w-5 h-5 text-gray-500" />
          </div>
          <div>
            <p class="text-xs text-gray-500">Email</p>
            <p class="font-medium text-gray-900">{{ authStore.user?.email }}</p>
          </div>
        </div>

        <div class="flex items-center gap-3">
          <div class="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center">
            <Icon name="lucide:map-pin" class="w-5 h-5 text-gray-500" />
          </div>
          <div>
            <p class="text-xs text-gray-500">Zone de livraison</p>
            <p class="font-medium text-gray-900">{{ agentStats.zone }}</p>
          </div>
        </div>
      </div>
    </div>

    <!-- Quick Actions -->
    <div class="space-y-3">
      <button 
        @click="showEditModal = true"
        class="w-full flex items-center gap-3 p-4 bg-white rounded-xl shadow-sm border border-gray-100"
      >
        <div class="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center">
          <Icon name="lucide:edit" class="w-5 h-5 text-blue-600" />
        </div>
        <span class="flex-1 text-left font-medium text-gray-900">Modifier mon profil</span>
        <Icon name="lucide:chevron-right" class="w-5 h-5 text-gray-400" />
      </button>

      <button 
        @click="authStore.logout()"
        class="w-full flex items-center gap-3 p-4 bg-white rounded-xl shadow-sm border border-gray-100"
      >
        <div class="w-10 h-10 rounded-full bg-red-100 flex items-center justify-center">
          <Icon name="lucide:log-out" class="w-5 h-5 text-red-600" />
        </div>
        <span class="flex-1 text-left font-medium text-red-600">Se déconnecter</span>
        <Icon name="lucide:chevron-right" class="w-5 h-5 text-gray-400" />
      </button>
    </div>

    <!-- Edit Modal -->
    <UModal v-model="showEditModal">
      <div class="p-6">
        <h3 class="text-lg font-semibold text-gray-900 mb-4">Modifier mon profil</h3>

        <div class="space-y-4">
          <UFormGroup label="Prénom">
            <UInput v-model="editForm.firstName" placeholder="Prénom" />
          </UFormGroup>

          <UFormGroup label="Nom">
            <UInput v-model="editForm.lastName" placeholder="Nom" />
          </UFormGroup>

          <UFormGroup label="Téléphone">
            <UInput v-model="editForm.phone" placeholder="Téléphone" />
          </UFormGroup>
        </div>

        <div class="flex gap-3 mt-6">
          <UButton color="gray" variant="outline" class="flex-1" @click="showEditModal = false">
            Annuler
          </UButton>
          <UButton color="primary" class="flex-1" :loading="saving" @click="saveProfile">
            Enregistrer
          </UButton>
        </div>
      </div>
    </UModal>
  </div>
</template>

<script setup lang="ts">
definePageMeta({
  layout: 'livreur',
  middleware: ['livreur']
})

const authStore = useAuthStore()
const { client } = useSupabase()
const toast = useToast()

// State
const showEditModal = ref(false)
const saving = ref(false)
const agentStats = ref({
  totalDeliveries: 0,
  rating: '5.0',
  zone: "N'Djamena",
  phone: ''
})

// Edit form
const editForm = ref({
  firstName: authStore.user?.firstName || '',
  lastName: authStore.user?.lastName || '',
  phone: authStore.user?.phone || ''
})

// Fetch agent stats
const fetchAgentStats = async () => {
  if (!authStore.user) return

  try {
    const { data } = await client
      .from('delivery_agents')
      .select('*')
      .eq('user_id', authStore.user.id)
      .single()

    if (data) {
      agentStats.value = {
        totalDeliveries: data.total_deliveries || 0,
        rating: Number(data.rating).toFixed(1),
        zone: data.zone || "N'Djamena",
        phone: data.phone || ''
      }
    }
  } catch (error) {
    console.error('Error fetching agent stats:', error)
  }
}

// Save profile
const saveProfile = async () => {
  saving.value = true

  try {
    const result = await authStore.updateProfile({
      firstName: editForm.value.firstName,
      lastName: editForm.value.lastName,
      phone: editForm.value.phone
    })

    if (result.success) {
      toast.add({ title: 'Succès', description: 'Profil mis à jour', color: 'green' })
      showEditModal.value = false
    } else {
      toast.add({ title: 'Erreur', description: result.error, color: 'red' })
    }
  } finally {
    saving.value = false
  }
}

// Watch for modal open to reset form
watch(showEditModal, (open) => {
  if (open) {
    editForm.value = {
      firstName: authStore.user?.firstName || '',
      lastName: authStore.user?.lastName || '',
      phone: authStore.user?.phone || agentStats.value.phone || ''
    }
  }
})

// Fetch on mount
onMounted(() => {
  fetchAgentStats()
})

useHead({
  title: 'Mon profil - TchadBox Livreur'
})
</script>
